unsafe extern "C" {
    // Safe to call without unsafe block
    pub safe fn sqrt(x: f64) -> f64;
    // Requires unsafe block to call
    pub unsafe fn free(ptr: *mut core::ffi::c_void);
}

// 2024: lifetime 'a is implicitly captured
fn filter<'a>(data: &'a [u8]) -> impl Iterator<Item = &'a u8> {
    data.iter().filter(|b| **b > 0)
}

// Opt out of capturing specific lifetimes:
fn owned_result<'a>(x: &'a str) -> impl Sized + use<> {
    x.to_string()
}

