let _: () = fallible_fn()?;
// Or:
fallible_fn::<()>()?;

// CORRECT: explicit return in closure
run(|| -> () { panic!("explicit") });

// WRONG: relies on old () fallback
// fallible_fn()?;  // T inferred as ! in 2024

// WRONG in 2024:
// fn gen() { ... }  // 'gen' is reserved

// CORRECT:
fn generate() { /* renamed from gen */ }
// Or use raw identifier if needed:
fn r#gen() { /* raw identifier escape */ }

let boxed: Box<[u32]> = vec![1, 2, 3].into_boxed_slice();

// 2024: yields owned u32
for val in boxed {
    println!("{val}");  // val: u32
}

// If you need references:
let boxed2: Box<[u32]> = vec![4, 5, 6].into_boxed_slice();
for r in boxed2.iter() {
    println!("{r}");  // r: &u32
}

