use std::ptr::addr_of;
use std::sync::Mutex;

// WRONG: reference to static mut
// static mut COUNTER: u32 = 0;
// let r = unsafe { &COUNTER };  // ERROR

// CORRECT: raw pointer
static mut COUNTER: u32 = 0;
let ptr = unsafe { addr_of!(COUNTER) };

// BETTER: use sync primitives
static COUNTER: Mutex<u32> = Mutex::new(0);

// In Rust 2024: Future and IntoFuture are in prelude
// No need for: use std::future::Future;

async fn process() -> Result<(), Error> {
    let fut = async { compute().await };
    fut.await
}

// IntoFuture enables .await on non-Future types
