function* fibonacci(): IterableIterator<number> {
  let [a, b] = [0, 1];
  while (true) { yield a; [a, b] = [b, a + b]; }
}

const first10Even = fibonacci()
  .filter(n => n % 2 === 0)
  .take(10)
  .toArray();

